import chalk from "chalk";
import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { basename, join } from "node:path";
import { globSync } from "glob";
import type { CaiConfig, DriftCheckerName, DriftIssue, IssueCode } from "./types.js";
import { runDriftCheck } from "./drift/index.js";
import { syncToolConfigs } from "./drift/checkers/tool-configs.js";
import { rebuildPatternIndex } from "./pattern/index.js";

type FixActionName =
  | "sync-tool-configs"
  | "rebuild-pattern-index"
  | "document-scripts"
  | "normalize-path-references";

export interface FixActionResult {
  action: FixActionName;
  changed: string[];
}

export interface FixRunResult {
  applied: FixActionResult[];
  skipped: FixActionResult[];
  initialIssueCount: number;
  remainingIssueCount: number;
}

const FIXABLE_ISSUES = new Map<IssueCode, FixActionName>([
  ["TOOL_CONFIG_OUT_OF_SYNC", "sync-tool-configs"],
  ["INDEX_MISSING_ENTRY", "rebuild-pattern-index"],
  ["INDEX_ORPHAN_ENTRY", "rebuild-pattern-index"],
  ["UNDOCUMENTED_SCRIPT", "document-scripts"],
  ["MISSING_PATH", "normalize-path-references"],
]);

export async function runAutoFix(
  config: CaiConfig,
  opts: { dryRun?: boolean; only?: DriftCheckerName[]; skip?: DriftCheckerName[] } = {}
): Promise<FixRunResult> {
  const initialReport = await runDriftCheck(config, {
    only: opts.only,
    skip: opts.skip,
  });
  const actions = collectFixActions(config, initialReport.issues);

  const applied: FixActionResult[] = [];
  const skipped: FixActionResult[] = [];

  for (const action of actions) {
    const preview = describeFixAction(action, config, initialReport.issues);
    if (preview.changed.length === 0) continue;

    if (opts.dryRun) {
      skipped.push(preview);
      continue;
    }

    const result = applyFixAction(config, action, initialReport.issues);
    if (result.changed.length > 0) {
      applied.push(result);
    }
  }

  const finalReport = (opts.dryRun || actions.length === 0)
    ? initialReport
    : await runDriftCheck(config, {
        only: opts.only,
        skip: opts.skip,
      });

  return {
    applied,
    skipped,
    initialIssueCount: initialReport.issues.length,
    remainingIssueCount: finalReport.issues.length,
  };
}

const ACTION_LABELS: Record<string, string> = {
  "sync-tool-configs": "Sync tool config files",
  "rebuild-pattern-index": "Rebuild patterns/INDEX.md",
  "document-scripts": "Add undocumented scripts to setup.md",
  "normalize-path-references": "Normalize stale path references",
};

export function printFixResult(result: FixRunResult, opts: { dryRun?: boolean } = {}): void {
  const b   = chalk.bold;
  const dim = chalk.dim;

  console.log();
  if (opts.dryRun) {
    console.log(`  ${b("cai fix")} ${dim("· dry run — no changes written")}`);
    console.log();
    if (result.skipped.length === 0) {
      console.log(`  ${chalk.cyan("ℹ")} ${dim("No auto-fixable scaffold drift found.")}`);
      console.log(`     ${dim("Run ")}${chalk.white("cai sync")}${dim(" to let AI update the remaining docs.")}`);
    } else {
      for (const action of result.skipped) {
        const label = ACTION_LABELS[action.action] ?? action.action;
        const files = action.changed.length > 0 ? chalk.cyan(action.changed.join(", ")) : dim("(no file changes)");
        console.log(`  ${chalk.yellow("⚠")} ${label} — ${files}`);
      }
    }
    console.log();
    return;
  }

  console.log(`  ${b("cai fix")} ${dim("· updating scaffold docs")}`);
  console.log();

  if (result.applied.length === 0) {
    console.log(`  ${chalk.cyan("ℹ")} ${dim("No auto-fixable scaffold drift found.")}`);
    console.log();
    console.log(`     ${dim("Run ")}${chalk.white("cai sync")}${dim(" to let AI update the remaining docs.")}`);
  } else {
    for (const action of result.applied) {
      const label = ACTION_LABELS[action.action] ?? action.action;
      const files = action.changed.length > 0 ? `  ${dim("→")} ${chalk.cyan(action.changed.join(", "))}` : "";
      console.log(`  ${chalk.green("✔")} ${label}${files}`);
    }
    console.log();
    const fixed = result.initialIssueCount - result.remainingIssueCount;
    if (result.remainingIssueCount > 0) {
      console.log(dim(`  ${fixed} issue${fixed !== 1 ? "s" : ""} resolved · ${result.remainingIssueCount} remaining`));
      console.log(`  ${chalk.cyan("ℹ")} ${dim("Run ")}${chalk.white("cai sync")}${dim(" to let AI fix the rest.")}`);
    } else {
      console.log(`  ${chalk.green("✔")} ${chalk.green("All issues resolved.")}`);
    }
  }
  console.log();
}

function collectFixActions(config: CaiConfig, issues: DriftIssue[]): FixActionName[] {
  const actions = new Set<FixActionName>();
  for (const issue of issues) {
    const action = FIXABLE_ISSUES.get(issue.code);
    if (!action) continue;
    if (!isFixActionAvailable(action, config, issues)) continue;
    actions.add(action);
  }
  return [...actions];
}

function isFixActionAvailable(
  action: FixActionName,
  config: CaiConfig,
  issues: DriftIssue[]
): boolean {
  switch (action) {
    case "sync-tool-configs":
    case "rebuild-pattern-index":
      return true;
    case "document-scripts":
      return findUndocumentedScripts(config, issues).length > 0;
    case "normalize-path-references":
      return findPathNormalizationTargets(config, issues).length > 0;
  }
}

function describeFixAction(
  action: FixActionName,
  config: CaiConfig,
  issues: DriftIssue[]
): FixActionResult {
  switch (action) {
    case "sync-tool-configs":
      return {
        action,
        changed: [
          ...new Set(
            issues
              .filter((issue) => issue.code === "TOOL_CONFIG_OUT_OF_SYNC")
              .map((issue) => issue.file)
          ),
        ],
      };
    case "rebuild-pattern-index":
      return { action, changed: ["patterns/INDEX.md"] };
    case "document-scripts":
      return {
        action,
        changed: findUndocumentedScripts(config, issues).length > 0 ? [pickScriptDocPath(config)] : [],
      };
    case "normalize-path-references":
      return {
        action,
        changed: [...new Set(findPathNormalizationTargets(config, issues).map((target) => target.file))],
      };
  }
}

function applyFixAction(config: CaiConfig, action: FixActionName, issues: DriftIssue[]): FixActionResult {
  switch (action) {
    case "sync-tool-configs": {
      const result = syncToolConfigs(config.projectRoot);
      return {
        action,
        changed: result.updated,
      };
    }
    case "rebuild-pattern-index": {
      const result = rebuildPatternIndex(config);
      return {
        action,
        changed: [result.file],
      };
    }
    case "document-scripts": {
      const result = addScriptDocumentationStubs(config, issues);
      return {
        action,
        changed: result ? [result] : [],
      };
    }
    case "normalize-path-references": {
      return {
        action,
        changed: normalizePathReferences(config, issues),
      };
    }
  }
}

function addScriptDocumentationStubs(
  config: CaiConfig,
  issues: DriftIssue[]
): string | null {
  const scripts = findUndocumentedScripts(config, issues);
  if (scripts.length === 0) return null;

  const uniqueScripts = [...new Set(scripts)].sort();
  const relativeDocPath = pickScriptDocPath(config);
  const absoluteDocPath = join(config.scaffoldRoot, relativeDocPath);
  if (!existsSync(absoluteDocPath)) return null;

  const content = readFileSync(absoluteDocPath, "utf8");
  const updated = injectScriptBullets(content, uniqueScripts);
  if (updated === content) return relativeDocPath;

  writeFileSync(absoluteDocPath, updated, "utf8");
  return relativeDocPath;
}

function findUndocumentedScripts(
  config: CaiConfig,
  issues: DriftIssue[]
): string[] {
  const relativeDocPath = pickScriptDocPath(config);
  const absoluteDocPath = join(config.scaffoldRoot, relativeDocPath);
  if (!existsSync(absoluteDocPath)) return [];

  return [
    ...new Set(
      issues
        .filter((issue) => issue.code === "UNDOCUMENTED_SCRIPT")
        .map((issue) => issue.message.match(/Script "(.+?)"/)?.[1] ?? null)
        .filter((value): value is string => Boolean(value))
    ),
  ].sort();
}

function pickScriptDocPath(config: CaiConfig): string {
  const preferred = ["context/setup.md", "SETUP.md"];
  for (const relativePath of preferred) {
    if (existsSync(join(config.scaffoldRoot, relativePath))) {
      return relativePath;
    }
  }
  return "context/setup.md";
}

function injectScriptBullets(content: string, scripts: string[]): string {
  const heading = "## Common Commands";
  const existingScriptNames = scripts.filter((script) => content.includes(`\`${script}\``));
  const missingScripts = scripts.filter((script) => !existingScriptNames.includes(script));
  if (missingScripts.length === 0) return content;

  const lines = content.split("\n");
  const headingIndex = lines.findIndex((line) => line.trim() === heading);
  const bullets = missingScripts.map(
    (script) => `- \`${script}\` — [AUTO-FIX] document what this command does and when to use it`
  );

  if (headingIndex === -1) {
    return `${content}${content.endsWith("\n") ? "" : "\n"}\n${heading}\n${bullets.join("\n")}\n`;
  }

  let insertAt = headingIndex + 1;
  while (insertAt < lines.length && lines[insertAt].trim().startsWith("<!--")) {
    while (insertAt < lines.length && !lines[insertAt].includes("-->")) {
      insertAt++;
    }
    insertAt++;
  }
  while (insertAt < lines.length && lines[insertAt].trim() === "") {
    insertAt++;
  }

  lines.splice(insertAt, 0, ...bullets);
  return `${lines.join("\n")}${content.endsWith("\n") ? "" : "\n"}`;
}

function normalizePathReferences(
  config: CaiConfig,
  issues: DriftIssue[]
): string[] {
  const targets = findPathNormalizationTargets(config, issues);
  const changed = new Set<string>();

  for (const target of targets) {
    const absolutePath = join(config.scaffoldRoot, target.file);
    if (!existsSync(absolutePath)) continue;

    const content = readFileSync(absolutePath, "utf8");
    const updated = replacePathReference(content, target);
    if (updated === content) continue;

    writeFileSync(absolutePath, updated, "utf8");
    changed.add(target.file);
  }

  return [...changed].sort();
}

function findPathNormalizationTargets(
  config: CaiConfig,
  issues: DriftIssue[]
): Array<{ file: string; from: string; to: string; line: number | null }> {
  const targets: Array<{ file: string; from: string; to: string; line: number | null }> = [];
  const seen = new Set<string>();

  for (const issue of issues) {
    if (issue.code !== "MISSING_PATH" || !issue.claim) continue;
    if (issue.claim.intent === "example" || issue.claim.confidence === "low") continue;
    const match = resolveUniquePathMatch(config.projectRoot, issue.claim.value);
    if (!match || match === issue.claim.value) continue;

    const key = `${issue.file}:${issue.line}:${issue.claim.value}:${match}`;
    if (seen.has(key)) continue;
    seen.add(key);
    targets.push({
      file: issue.file,
      from: issue.claim.value,
      to: match,
      line: issue.line,
    });
  }

  return targets;
}

function resolveUniquePathMatch(projectRoot: string, claimedPath: string): string | null {
  const fileName = basename(claimedPath);
  if (!fileName || fileName === claimedPath) return null;

  const matches = globSync(`**/${fileName}`, {
    cwd: projectRoot,
    ignore: ["node_modules/**", ".git/**", "dist/**", "build/**", ".cai/**", ".context-condensing/**"],
  });

  const uniqueMatches = [...new Set(matches)].sort();
  if (uniqueMatches.length !== 1) return null;
  return uniqueMatches[0];
}

function replacePathReference(
  content: string,
  target: { from: string; to: string; line: number | null }
): string {
  const lines = content.split("\n");
  if (target.line && target.line > 0 && target.line <= lines.length) {
    const index = target.line - 1;
    const currentLine = lines[index];
    const updatedLine = replacePathReferenceInLine(currentLine, target.from, target.to);
    if (updatedLine !== currentLine) {
      lines[index] = updatedLine;
      return lines.join("\n");
    }
  }

  return content;
}

function replacePathReferenceInLine(line: string, from: string, to: string): string {
  // Replace all occurrences on the line, preferring delimited forms to avoid false positives
  const codeSpan = `\`${from}\``;
  if (line.includes(codeSpan)) {
    return line.replaceAll(codeSpan, `\`${to}\``);
  }

  const quoted = `"${from}"`;
  if (line.includes(quoted)) {
    return line.replaceAll(quoted, `"${to}"`);
  }

  const singleQuoted = `'${from}'`;
  if (line.includes(singleQuoted)) {
    return line.replaceAll(singleQuoted, `'${to}'`);
  }

  // Bare replacement — only if surrounded by non-word/non-path chars to avoid partial matches
  const escaped = from.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const re = new RegExp(`(?<![\\w/])${escaped}(?![\\w])`, "g");
  return line.replace(re, to);
}
