// ── Layer 2: Drift Detection ──
program
  .command("check")
  .description("Detect drift between scaffold files and codebase reality")
  .option("--json", "Output full drift report as JSON")
  .option("--quiet", "Single-line summary only")
  .option("--verbose", "Print detailed drift diagnostics")
  .option("--explain <query>", "Explain matching drift issues by code, file, or message")
  .option("--only <checkers>", "Run only the listed checkers (comma-separated)")
  .option("--skip <checkers>", "Skip the listed checkers (comma-separated)")
  .option("--stale-days <days>", "Override staleness warning threshold in days", Number)
  .option("--stale-commits <count>", "Override staleness warning threshold in commits", Number)
  .option("--incremental", "Only check scaffold files that have uncommitted changes")
  .option("--fast", "Skip slow checkers (staleness) for faster CI runs")
  .option("--fix", "Run sync to fix any issues found")
  .option("--tokens", "Show token cost per scaffold context file")
  .option("--history", "Show drift score trend over time")
  .action(async (opts) => {
    try {
      if (opts.explain && (opts.json || opts.quiet)) {
        throw new Error("--explain cannot be combined with --json or --quiet");
      }

      // --tokens: show token costs and exit
      if (opts.tokens) {
        const config = findConfig();
        printTokenReport(config);
        return;
      }

      // --history: show trend instead of running a check
      if (opts.history) {
        const config = findConfig();
        const { readHistory, summarizeHistory } = await import("./drift/history.js");
        const entries = readHistory(config.projectRoot);
        const summary = summarizeHistory(entries);

        if (!summary) {
          console.log(chalk.dim(`No drift history yet — run ${chalk.white("cai check")} a few times to build a trend.`));
          return;
        }

        if (opts.json) {
          console.log(JSON.stringify({ entries, summary }, null, 2));
          return;
        }

        const color = (s: number) => s >= 80 ? chalk.green : s >= 50 ? chalk.yellow : chalk.red;
        const arrow = summary.delta === null ? "" :
          summary.delta > 0 ? chalk.green(`▲ +${summary.delta}`) :
          summary.delta < 0 ? chalk.red(`▼ ${summary.delta}`) :
          chalk.dim("◇ no change");

        console.log();
        console.log(chalk.bold(`  Drift score history — ${summary.count} run${summary.count !== 1 ? "s" : ""}`));
        console.log();
        console.log(`  ${chalk.dim("current")}    ${color(summary.current)(`${summary.current}/100`)}  ${arrow}`);
        console.log(`  ${chalk.dim("best")}       ${color(summary.best)(`${summary.best}/100`)}`);
        console.log(`  ${chalk.dim("worst")}      ${color(summary.worst)(`${summary.worst}/100`)}`);
        console.log(`  ${chalk.dim("average")}    ${color(summary.average)(`${summary.average}/100`)}`);
        console.log();
        console.log(`  ${chalk.dim("trend")}      ${chalk.cyan(summary.sparkline)}  ${chalk.dim("(last 30 runs)")}`);
        console.log();

        // Show recent runs as a small table
        const recent = entries.slice(-5).reverse();
        console.log(chalk.dim("  Recent runs"));
        for (const e of recent) {
          const when = new Date(e.ts).toISOString().replace("T", " ").slice(0, 16);
          const scoreStr = e.weightedScore !== undefined
            ? `${e.score}/${e.weightedScore}`
            : `${e.score}`;
          const issues = `${e.errors}E ${e.warnings}W`;
          console.log(`    ${chalk.dim(when)}   ${color(e.score)(scoreStr.padEnd(8))}  ${chalk.dim(issues)}`);
        }
        console.log();
        return;
      }

      const config = findConfig();
      const only = parseCheckerList(opts.only);
      const skip = parseCheckerList(opts.skip);
      // --fast skips the staleness checker (most expensive due to git operations)
      const effectiveSkip = opts.fast
        ? [...(skip ?? []), "staleness" as const]
        : skip;
      const { runDriftCheck } = await import("./drift/index.js");
      const report = await runDriftCheck(config, {
        verbose: (opts.verbose || Boolean(opts.explain)) && !opts.json && !opts.quiet,
        staleDays: opts.staleDays,
        staleCommits: opts.staleCommits,
        only,
        skip: effectiveSkip,
        incremental: opts.incremental,
      });

      const isNonInteractive = opts.json || opts.quiet || opts.explain || opts.fix;

      if (opts.json) {
        reportJSON(report);
      } else if (opts.quiet) {
        reportQuiet(report);
      } else if (opts.explain) {
        reportExplain(report, opts.explain);
      } else if (opts.fix) {
        // --fix: auto-fix then sync remaining
        reportConsole(report, { verbose: opts.verbose });
        const fixResult = await runAutoFix(config, { only, skip });
        printFixResult(fixResult);
        const postFixReport = await runDriftCheck(config, { staleDays: opts.staleDays, staleCommits: opts.staleCommits, only, skip });
        if (postFixReport.issues.some((i) => i.severity === "error")) {
          const { runSync } = await import("./sync/index.js");
          await runSync(config, {});
        }
        return;
      } else {
        // Interactive mode: show report, then guide through next steps
        reportConsole(report, { verbose: opts.verbose });
        const hasIssues = report.issues.some((i) => i.severity === "error" || i.severity === "warning");
        if (hasIssues && process.stdout.isTTY) {
          await runGuidedFlow(config, { verbose: opts.verbose });
          return;
        }
      }

      const hasErrors = report.issues.some((i) => i.severity === "error");
      if (hasErrors && isNonInteractive) process.exit(1);
    } catch (err) {
      printError(err);
      process.exit(1);
    }
  });

