patternCmd
  .command("library")
  .description("List all patterns in your global library (use --where for sync setup)")
  .option("--json", "Output as JSON")
  .option("--where", "Show the library path and how to sync it across devices")
  .option("--history <name>", "Show all versions of a specific pattern")
  .action(async (opts) => {
    try {
      const { listLibrary, libraryRoot, libraryStats, listVersions } = await import("./pattern/library.js");

      if (opts.history) {
        const versions = listVersions(opts.history)
          .sort((a, b) => (b.version ?? 1) - (a.version ?? 1));
        if (versions.length === 0) {
          console.log(chalk.dim(`No pattern named "${opts.history}" in your library.`));
          return;
        }
        console.log();
        console.log(chalk.bold(`  ${opts.history} — ${versions.length} version${versions.length !== 1 ? "s" : ""}`));
        console.log();
        for (const v of versions) {
          const versionLabel = v.version !== undefined ? `v${v.version}` : "v1";
          const date = v.createdAt.split("T")[0];
          console.log(`  ${chalk.green(versionLabel.padEnd(5))}  ${chalk.cyan(v.hash)}  ${chalk.dim(date)}`);
          console.log(`         ${chalk.dim(v.description)}`);
        }
        console.log();
        console.log(chalk.dim(`  Install a specific version with: ${chalk.white("cai pattern install <hash>")}`));
        console.log();
        return;
      }

      if (opts.where) {
        const root = libraryRoot();
        const usingEnv = Boolean(process.env.CAI_HOME);
        console.log();
        console.log(chalk.bold(`  Pattern library location`));
        console.log(`  ${chalk.cyan(root)}  ${usingEnv ? chalk.dim("(from CAI_HOME)") : chalk.dim("(default ~/.cai)")}`);
        console.log();
        console.log(chalk.bold(`  Sync across devices`));
        console.log(chalk.dim(`  Point CAI_HOME at a folder your cloud provider syncs:`));
        console.log();
        console.log(chalk.dim(`    # Dropbox`));
        console.log(`    export CAI_HOME=~/Dropbox/.cai`);
        console.log();
        console.log(chalk.dim(`    # iCloud Drive`));
        console.log(`    export CAI_HOME=~/Library/Mobile\\ Documents/com~apple~CloudDocs/.cai`);
        console.log();
        console.log(chalk.dim(`    # Syncthing / Resilio / etc — any synced folder works`));
        console.log(`    export CAI_HOME=~/Sync/.cai`);
        console.log();
        console.log(chalk.dim(`  Add the export to your shell config (.zshrc / .bashrc) and re-open the terminal.`));
        console.log(chalk.dim(`  Patterns are content-hashed, so simultaneous shares from two machines never collide.`));
        console.log();
        return;
      }

      const entries = listLibrary();
      if (opts.json) {
        console.log(JSON.stringify(entries, null, 2));
        return;
      }
      if (entries.length === 0) {
        console.log(chalk.dim(`No patterns in library yet.`));
        console.log(chalk.dim(`  ${libraryRoot()}`));
        console.log(chalk.dim(`  Share one with: ${chalk.white("cai pattern share <name>")}`));
        console.log(chalk.dim(`  Set up cross-device sync: ${chalk.white("cai pattern library --where")}`));
        return;
      }
      const stats = libraryStats();
      console.log(chalk.bold(`\n  CAI pattern library — ${entries.length} pattern${entries.length !== 1 ? "s" : ""}`));
      console.log(chalk.dim(`  ${libraryRoot()}  ·  ${(stats.bytes / 1024).toFixed(1)} KB\n`));
      for (const e of entries) {
        const stack = e.stack ? chalk.dim(`[${e.stack}]`) : "";
        const versionLabel = e.version && e.version > 1 ? chalk.green(`v${e.version}`) : chalk.dim(`v${e.version ?? 1}`);
        console.log(`  ${chalk.cyan(e.hash)}  ${versionLabel}  ${chalk.bold(e.name.padEnd(28))}  ${stack}`);
        console.log(`                  ${chalk.dim(e.description)}`);
      }
      console.log();
      console.log(chalk.dim(`  Sync across devices: ${chalk.white("cai pattern library --where")}`));
      console.log();
    } catch (err) {
      printError(err);
      process.exit(1);
    }
  });

