patternCmd
  .command("recurring")
  .description("Find recurring task types in your commit history and draft patterns for them")
  .option("--write", "Write the drafts to .cai/patterns/ instead of just listing them")
  .action(async (opts) => {
    try {
      const config = findConfig();
      const { readRecentCommits, clusterCommits } = await import("./pattern/cluster.js");
      const { buildSuggestionDraft } = await import("./pattern/auto-suggest.js");
      const commits = readRecentCommits(config.projectRoot);
      const clusters = clusterCommits(commits);

      if (clusters.length === 0) {
        console.log(chalk.dim(`No recurring task types found in the last 30 days.`));
        console.log(chalk.dim(`  Need at least 3 commits of the same kind for a cluster.`));
        return;
      }

      console.log(chalk.bold(`\n  Recurring task types — ${clusters.length} cluster${clusters.length !== 1 ? "s" : ""}\n`));
      const today = new Date().toISOString().split("T")[0];
      const { writeFileSync, existsSync, mkdirSync } = await import("node:fs");

      for (const c of clusters) {
        console.log(`  ${chalk.cyan(c.taskType.padEnd(20))} ${chalk.green(`${c.commits.length}×`)}  ${chalk.dim(`last seen ${c.lastSeen.split("T")[0]}`)}`);
        if (c.commonFiles.length > 0) {
          console.log(`    ${chalk.dim("recurring files: " + c.commonFiles.slice(0, 3).join(", "))}`);
        }

        if (opts.write) {
          const filename = `recurring-${c.taskType}-${today}.md`;
          const dest = join(config.scaffoldRoot, "patterns", filename);
          if (existsSync(dest)) {
            console.log(`    ${chalk.yellow("⚠")} ${chalk.dim(`skipped: ${filename} already exists`)}`);
          } else {
            mkdirSync(join(config.scaffoldRoot, "patterns"), { recursive: true });
            writeFileSync(dest, buildSuggestionDraft(c, today), "utf8");
            console.log(`    ${chalk.green("✓")} ${chalk.dim(`wrote ${filename}`)}`);
          }
        }
      }
      console.log();
      if (!opts.write) {
        console.log(chalk.dim(`  Run with ${chalk.white("--write")} to draft pattern files for each cluster.`));
        console.log();
      }
    } catch (err) {
      printError(err);
      process.exit(1);
    }
  });

patternCmd
  .command("install <query>")
