learnCmd
  .command("review")
  .description("Show recurring corrections in your recent prompts")
  .option("--days <n>", "Look back N days (default: 14)", "14")
  .option("--stack <type>", "Only show corrections from prompts in this stack (e.g. package.json, go.mod, current)")
  .action(async (opts) => {
    try {
      const config = findConfig();
      const { readPrompts } = await import("./learn/recorder.js");
      const { detectCorrections, clusterCorrections, suggestRule } = await import("./learn/corrections.js");
      const days = parseInt(opts.days, 10);
      const sinceMs = Date.now() - days * 24 * 60 * 60 * 1000;
      const prompts = readPrompts(config.projectRoot, { sinceMs });

      // Resolve --stack current to the actual project stack
      let stackFilter: string | undefined = opts.stack;
      if (stackFilter === "current") {
        const { scanProjectModel } = await import("./scanner/manifest.js");
        stackFilter = scanProjectModel(config.projectRoot).rootManifest?.type ?? undefined;
        if (!stackFilter) {
          console.log(chalk.yellow(`⚠ No manifest detected in this project — falling back to all stacks.`));
        }
      }

      if (prompts.length === 0) {
        console.log(chalk.dim(`No recorded prompts in the last ${days} days.`));
        console.log(chalk.dim(`  Run ${chalk.white("cai learn enable")} to start recording.`));
        return;
      }

      const corrections = detectCorrections(prompts, { stack: stackFilter });
      const clusters = clusterCorrections(corrections);

      const stackLabel = stackFilter ? chalk.dim(` · stack: ${stackFilter}`) : "";
      console.log(chalk.bold(`\n  Session review — last ${days} days`) + stackLabel);
      console.log(chalk.dim(`  ${prompts.length} prompts · ${corrections.length} look like corrections · ${clusters.length} recurring\n`));

      if (clusters.length === 0) {
        console.log(chalk.dim(`  No recurring corrections detected. Either you're not correcting Claude often,`));
        console.log(chalk.dim(`  or each correction is unique. The recorder needs repeats to find patterns.`));
        return;
      }

      console.log(chalk.bold("  Recurring corrections — consider adding these to CLAUDE.md:\n"));
      for (const c of clusters.slice(0, 10)) {
        console.log(`  ${chalk.cyan(c.id)}  ${chalk.green(`${c.count}×`)}  ${c.example}  ${chalk.dim(`[${c.signal}]`)}`);
        console.log(`          ${chalk.dim("→ suggested rule:")} ${chalk.white(suggestRule(c))}`);
      }
      console.log();
      console.log(chalk.dim(`  Apply one with: ${chalk.white("cai learn write-rule <id>")}`));
      console.log();
    } catch (err) {
      printError(err);
      process.exit(1);
    }
  });

learnCmd
  .command("write-rule <id>")
  .description("Append a learned rule to CLAUDE.md under a managed section")
  .option("--days <n>", "Look back N days for the cluster (default: 14)", "14")
  .action(async (id, opts) => {
    try {
      const config = findConfig();
      const { readPrompts } = await import("./learn/recorder.js");
      const { detectCorrections, clusterCorrections, findClusterById, suggestRule, appendLearnedRule } = await import("./learn/corrections.js");
      const { existsSync, readFileSync, writeFileSync } = await import("node:fs");

      const days = parseInt(opts.days, 10);
      const sinceMs = Date.now() - days * 24 * 60 * 60 * 1000;
      const prompts = readPrompts(config.projectRoot, { sinceMs });
      const corrections = detectCorrections(prompts);
      const clusters = clusterCorrections(corrections);
      const cluster = findClusterById(clusters, id);

      if (!cluster) {
        console.error(chalk.red(`No cluster with id "${id}" in the last ${days} days.`));
        console.error(chalk.dim(`  Run ${chalk.white("cai learn review")} to see current cluster ids.`));
        process.exit(1);
      }

      const claudeMdPath = join(config.projectRoot, "CLAUDE.md");
      if (!existsSync(claudeMdPath)) {
        console.error(chalk.red(`CLAUDE.md not found at ${claudeMdPath}`));
        console.error(chalk.dim(`  Run ${chalk.white("cai setup")} first.`));
        process.exit(1);
      }

      const before = readFileSync(claudeMdPath, "utf8");
      const rule = suggestRule(cluster);

      if (before.includes(rule)) {
        console.log(chalk.yellow(`⚠ Rule already present in CLAUDE.md — nothing to do.`));
        return;
      }

      const after = appendLearnedRule(before, rule);
      writeFileSync(claudeMdPath, after, "utf8");

      console.log(chalk.green(`✓ Added to CLAUDE.md`));
      console.log(`  ${chalk.dim("rule:")} ${chalk.white(rule)}`);
      console.log(`  ${chalk.dim("cluster:")} ${cluster.count}× "${cluster.example}"`);
      console.log(chalk.dim(`  Section: <!-- cai:learn-start --> ... <!-- cai:learn-end -->`));
    } catch (err) {
      printError(err);
      process.exit(1);
    }
  });

