learnCmd
  .command("record")
  .description("Internal: read a prompt from stdin (called by Claude Code's UserPromptSubmit hook)")
  .action(async () => {
    try {
      const config = findConfig();
      const { recordPrompt, isLearnEnabled } = await import("./learn/recorder.js");
      if (!isLearnEnabled(config.projectRoot)) {
        return; // silent no-op when disabled
      }
      // Read all of stdin
      const chunks: Buffer[] = [];
      for await (const chunk of process.stdin) {
        chunks.push(chunk as Buffer);
      }
      const raw = Buffer.concat(chunks).toString("utf8").trim();
      if (!raw) return;

      // Try to parse as Claude Code hook JSON; fall back to raw text
      let prompt = raw;
      try {
        const parsed = JSON.parse(raw) as { prompt?: string; user_prompt?: string };
        prompt = parsed.prompt ?? parsed.user_prompt ?? raw;
      } catch {
        // raw text, that's fine
      }

      // Detect current stack so we can scope correction clusters per tech stack
      let stack: string | undefined;
      try {
        const { scanProjectModel } = await import("./scanner/manifest.js");
        stack = scanProjectModel(config.projectRoot).rootManifest?.type ?? undefined;
      } catch {
        // optional — never fail the hook over a missing manifest
      }

      recordPrompt(config.projectRoot, prompt, { source: "claude-code-hook", stack });
    } catch {
      // never fail the hook
    }
  });

