function parseCheckerList(input?: string): DriftCheckerName[] | undefined {
  if (!input) return undefined;
  const values = input
    .split(",")
    .map((value) => value.trim())
    .filter(Boolean);

  const invalid = values.filter(
    (value) => !AVAILABLE_DRIFT_CHECKERS.includes(value as (typeof AVAILABLE_DRIFT_CHECKERS)[number])
  );
  if (invalid.length > 0) {
    throw new Error(
      `Unknown checker(s): ${invalid.join(", ")}. Available: ${AVAILABLE_DRIFT_CHECKERS.join(", ")}`
    );
  }

  return values as DriftCheckerName[];
}
