import chalk from "chalk";
import {
  cpSync,
  existsSync,
  mkdirSync,
  readFileSync,
  readdirSync,
  rmSync,
  writeFileSync,
} from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { spawnSync } from "node:child_process";
import { ensureMcpRegistered, ensureCaiHooks, ensureLearnHook } from "./mcp/install.js";
import { generateRules } from "./rules.js";
import { enableLearn, isLearnEnabled } from "./learn/recorder.js";

// Must stay in sync with the "files" field in package.json
const BOOTSTRAP_ENTRIES = [
  ".tool-configs",
  "AGENTS.md",
  "CLAUDE.md",
  "LICENSE",
  "README.md",
  "ROUTER.md",
  "SETUP.md",
  "SYNC.md",
  "context",
  "dist",
  "mascot",
  "package.json",
  "patterns",
  "screenshots",
  "setup.sh",
  "sync.sh",
  "tsup.config.ts",
  "update.sh",
  "visualize.sh",
] as const;

export interface BootstrapResult {
  targetDir: string;
  copied: string[];
  setupRan?: boolean;
  mcpStatus?: "registered" | "already_registered" | "claude_not_found" | "failed";
  rulesGenerated?: number;
  skillsGenerated?: number;
  hooksInstalled?: number;
  /** True when correction recording was just activated (vs. already on). */
  learnEnabled?: boolean;
}

export function runBootstrap(opts: {
  targetDir?: string;
  sourceRoot?: string;
  force?: boolean;
} = {}): BootstrapResult {
  const sourceRoot = opts.sourceRoot ?? getPackageRoot();
  const projectRoot = resolve(opts.targetDir ?? process.cwd());
  const destination = join(projectRoot, ".cai");

  if (sourceRoot === destination) {
    throw new Error("Refusing to bootstrap CAI into itself.");
  }

  if (existsSync(destination)) {
    const hasContent = readdirSync(destination).length > 0;
    if (hasContent && !opts.force) {
      throw new Error(`.cai already exists in ${projectRoot}. Use --force to replace it.`);
    }
    rmSync(destination, { recursive: true, force: true });
  }

  mkdirSync(destination, { recursive: true });

  const copied: string[] = [];
  for (const entry of BOOTSTRAP_ENTRIES) {
    const from = join(sourceRoot, entry);
    if (!existsSync(from)) continue;
    const to = join(destination, entry);
    cpSync(from, to, { recursive: true });
    copied.push(entry);
  }

  // Strip HTML template comments from scaffold markdown files.
  // These comments guide humans during initial population but waste tokens
  // when Claude reads them in every session (~2,000-2,500 tokens total).
  stripTemplateComments(destination);

  const mcp = ensureMcpRegistered(projectRoot);
  const hooksInstalled = ensureCaiHooks(projectRoot);

  // Enable correction recording by default + install the UserPromptSubmit hook.
  // The recorder is local-only, gitignored, and never uploaded — opting in by
  // default makes the AI→You feedback loop work without requiring a separate step.
  // Run `cai learn forget` to wipe everything if you change your mind.
  const learnWasOff = !isLearnEnabled(projectRoot);
  if (learnWasOff) {
    enableLearn(projectRoot);
    ensureLearnHook(projectRoot);
  }

  // Generate .claude/rules/ from scaffold context
  let rulesGenerated = 0;
  try {
    const config = { projectRoot, scaffoldRoot: destination, settings: {} };
    const rules = generateRules(config);
    rulesGenerated = rules.written.length;
  } catch {
    // Non-fatal: rules generation can fail on first setup before content exists
  }

  // Generate .claude/skills/ for common CAI workflows
  const skillsGenerated = generateSkills(projectRoot);

  return {
    targetDir: destination,
    copied,
    mcpStatus: mcp.status,
    rulesGenerated,
    skillsGenerated,
    hooksInstalled,
    learnEnabled: learnWasOff,
  };
}

export function printBootstrapResult(result: BootstrapResult): void {
  const b = chalk.bold;
  const dim = chalk.dim;

  console.log();
  console.log(`  ${b("cai setup")} ${dim("· scaffold installed")}`);
  console.log();
  console.log(chalk.green(`  ✓ ${result.targetDir}`));
  console.log(dim(`  ${result.copied.length} entries written`));
  console.log();

  // Rules + MCP status
  if (result.rulesGenerated && result.rulesGenerated > 0) {
    console.log(chalk.green(`  ✓ ${result.rulesGenerated} path-scoped rules`) + dim(" — Claude loads context only when touching matching files"));
  }
  if (result.mcpStatus === "registered") {
    console.log(chalk.green(`  ✓ MCP server registered`) + dim(" — Claude can query context on-demand"));
  } else if (result.mcpStatus === "already_registered") {
    console.log(chalk.green(`  ✓ MCP server active`));
  } else if (result.mcpStatus === "claude_not_found") {
    console.log(dim(`  ℹ MCP: run ${chalk.white("cai mcp install")} to connect Claude once installed`));
  }
  if (result.skillsGenerated && result.skillsGenerated > 0) {
    console.log(chalk.green(`  ✓ ${result.skillsGenerated} skill${result.skillsGenerated !== 1 ? "s" : ""} generated`) + dim(" — use /cai-check and /cai-sync in Claude Code"));
  }
  if (result.hooksInstalled && result.hooksInstalled > 0) {
    console.log(
      chalk.green(`  ✓ ${result.hooksInstalled} Claude Code hook${result.hooksInstalled !== 1 ? "s" : ""} installed`) +
      dim(" — PreCompact, PreToolUse safety, Stop verify")
    );
  }
  if (result.learnEnabled) {
    console.log(
      chalk.green(`  ✓ Correction recording enabled`) +
      dim(" — local-only, gitignored, run cai learn forget to wipe")
    );
  }
  console.log();

  if (result.setupRan) {
    console.log(dim("  Run cai check to verify everything is in order."));
  } else {
    console.log(dim("  Run cai setup to initialise your project context."));
  }
  console.log();
}

export function runBootstrappedSetup(projectRoot: string): void {
  const setupScript = join(projectRoot, ".cai", "setup.sh");
  if (!existsSync(setupScript)) {
    throw new Error(`No setup script found at ${setupScript}`);
  }

  const result = spawnSync("bash", [setupScript], {
    cwd: projectRoot,
    stdio: "inherit",
  });

  if (result.error) {
    throw result.error;
  }

  // 130 = SIGINT (Ctrl+C), 143 = SIGTERM — user cancelled, not an error
  if (typeof result.status === "number" && result.status !== 0 && result.status !== 130 && result.status !== 143) {
    throw new Error(`.cai/setup.sh exited with code ${result.status}`);
  }
}

/** Strip template guidance comments from all markdown files in the scaffold.
 *  Preserves CAI merge markers (<!-- cai:start/end -->) and comments inside code blocks. */
function stripTemplateComments(scaffoldDir: string): void {
  const dirs = ["", "context", "patterns"];
  for (const sub of dirs) {
    const dir = sub ? join(scaffoldDir, sub) : scaffoldDir;
    if (!existsSync(dir)) continue;
    for (const entry of readdirSync(dir)) {
      if (!entry.endsWith(".md")) continue;
      const filePath = join(dir, entry);
      const content = readFileSync(filePath, "utf8");
      const stripped = stripCommentsPreservingMarkers(content);
      if (stripped !== content) {
        writeFileSync(filePath, stripped, "utf8");
      }
    }
  }
}

function stripCommentsPreservingMarkers(content: string): string {
  // Process line by line to skip code blocks
  const lines = content.split("\n");
  const out: string[] = [];
  let inCodeBlock = false;
  let inComment = false;

  for (const line of lines) {
    if (line.startsWith("```")) {
      inCodeBlock = !inCodeBlock;
      out.push(line);
      continue;
    }
    if (inCodeBlock) {
      out.push(line);
      continue;
    }

    // Preserve CAI merge markers
    if (line.includes("<!-- cai:")) {
      out.push(line);
      continue;
    }

    // Track multiline comments
    if (inComment) {
      if (line.includes("-->")) {
        inComment = false;
        // Drop the closing line (part of the template comment)
      }
      continue;
    }

    if (line.trimStart().startsWith("<!--")) {
      if (line.includes("-->")) {
        // Single-line comment — drop it
        continue;
      }
      // Start of multiline comment
      inComment = true;
      continue;
    }

    out.push(line);
  }

  // Clean up excessive blank lines left by removed comments
  return out.join("\n").replace(/\n{3,}/g, "\n\n");
}

/** Generate .claude/skills/ for common CAI workflows.
 *  Skills are Claude Code's slash-command system — users invoke them with /skill-name. */
function generateSkills(projectRoot: string): number {
  const skillsDir = join(projectRoot, ".claude", "skills");
  let count = 0;

  const skills: Array<{ name: string; content: string }> = [
    {
      name: "cai-check",
      content: `---
description: "Run CAI drift detection to verify scaffold docs match the codebase."
---

Run \`cai check\` in the project root and report the results. If the score is below 80, suggest running \`cai fix\` for safe auto-repairs.

If errors remain after fix, list the top 3 issues and suggest what to update.
`,
    },
    {
      name: "cai-sync",
      content: `---
description: "Fix all drift issues — safe auto-fixes first, then AI-assisted updates."
---

1. Run \`cai fix\` to apply safe deterministic repairs.
2. Check results with \`cai check --quiet\`.
3. If issues remain, read each affected .cai/ file and fix the drift issues directly.
4. After fixing, run \`cai check\` again to verify score is 100.
5. Do not modify source code files — only update .cai/ scaffold documentation.
`,
    },
  ];

  for (const skill of skills) {
    try {
      const dir = join(skillsDir, skill.name);
      const filePath = join(dir, "SKILL.md");
      if (existsSync(filePath)) continue;
      mkdirSync(dir, { recursive: true });
      writeFileSync(filePath, skill.content, "utf8");
      count++;
    } catch {
      // Non-fatal: skills are optional convenience features
    }
  }

  return count;
}

function getPackageRoot(): string {
  return dirname(dirname(fileURLToPath(import.meta.url)));
}
